    function syncToothNudgeState(){const single=!isRangeConstruction();[{part:'start',field:toothStartField,val:ts.value,hide:false},{part:'end',field:toothEndField,val:te.value,hide:single}].forEach(({part,field,val,hide})=>{if(hide)return;const left=field.querySelector('[data-nudge="-1"]'),right=field.querySelector('[data-nudge="1"]');if(part==='start'&&val===''){left.disabled=false;right.disabled=false;return}if(val===''){left.disabled=right.disabled=true;return}const cur=+val,seq=jawForTooth(cur);if(!seq||!seq.includes(cur)){left.disabled=right.disabled=true;return}const idx=seq.indexOf(cur);left.disabled=idx<=0;right.disabled=idx>=seq.length-1})}
