    async function ensureDeliveryDate(){if(deadline.value||selectedDate)return;syncImpressionToday();const startIso=impression.value,endIso=toIsoDate(addDays(new Date(startIso),90));const result=await ordersApi.dateAvailability(draft(startIso,startIso,endIso));const j=result.data;if(result.ok&&j.dates){deliveryMinimumDate=j.minimumDate||'';syncDeliverySelection(j.dates)}}async function loadDates(){if(!deliveryCalendar)return;hideDateReasonPop();syncImpressionToday();const request=++calendarRequest;const month=calendarMonth,bounds=MonthCalendar.bounds(month),startIso=toIsoDate(bounds.start),endIso=toIsoDate(bounds.end);const result=await ordersApi.dateAvailability(draft(deadline.value||selectedDate||startIso,startIso,endIso));const j=result.data;if(request!==calendarRequest)return;if(!result.ok){dateMsg.textContent=j.error;dateMsg.className='msg err';return}deliveryMinimumDate=j.minimumDate||'';const changed=syncDeliverySelection(j.dates);const picked=deadline.value||selectedDate;if(changed&&picked){deliveryPickSkips=0;const want=monthForIso(picked);if(want.getTime()!==calendarMonth.getTime()){calendarMonth=want;return loadDates()}}else if(!firstSelectableDate(j.dates)&&deliveryPickSkips<18){deliveryPickSkips++;calendarMonth=new Date(calendarMonth.getFullYear(),calendarMonth.getMonth()+1,1);return loadDates()}deliveryPickSkips=0;dateMsg.textContent='';dateMsg.className='msg hidden';updateSelectedDeliveryDisplay();hideDateReasonPop();const byDate=new Map(j.dates.map(d=>[d.date,d]));const options={month,renderCell:ctx=>renderDeliveryDateCell(ctx,byDate,month),onMonthChange:m=>{calendarMonth=m;if(step===3)loadDates()}};if(!deliveryCalendarInstance)deliveryCalendarInstance=MonthCalendar.create(deliveryCalendar,options);else deliveryCalendarInstance.setOptions(options)}
    async function createOrder(){const msg=validateBeforeStep(5);if(msg)return showErr(msg);await ensureDeliveryDate();const delivery=deadline.value||selectedDate;if(!delivery)return showErr('No delivery date available.');const result=editMode?await ordersApi.updateOrder(editingOrder.orderCode,draft(delivery)):await ordersApi.createOrder(draft(delivery));const j=result.data;if(!result.ok)return showErr(j.error||'Could not save order.');if(editMode){const savedCode=j.order.orderCode;editingOrder=null;editMode=false;reviewOrder=null;orderFlowBaselineState='';listHighlightCode=savedCode;await goOrderReview(savedCode,{skipDirtyGuard:true});return}createdOrder=j.order;code.textContent=j.order.shortenedOrderCode||j.order.orderCode;completedSteps.add(3);completedSteps.add(4);completedSteps.add(5);orderCreated=true;orderFlowBaselineState='';await goCreatedOrder(j.order.orderCode,{skipDirtyGuard:true});}
