    function routeStepValue(raw){const n=Number.parseInt(raw,10);return Number.isFinite(n)?n:NaN}
    function flowRoutePath(stepToOpen){if(editMode&&editingOrder)return `edit/${encodeURIComponent(editingOrder.orderCode)}/${stepToOpen}`;return `new/${stepToOpen}`}
    function validOrderFlowStepOrReplace(kind,code,rawStep){const requested=routeStepValue(rawStep);if(!Number.isInteger(requested)||requested<1){ordersRouter.replace(kind==='edit'?`edit/${encodeURIComponent(code)}/1`:'new/1',{skipGuard:true});return null}if(requested>4){const fallback=Math.min(Math.max(step||1,1),4);ordersRouter.replace(kind==='edit'?`edit/${encodeURIComponent(code)}/${fallback}`:`new/${fallback}`,{skipGuard:true});return null}return requested}
