    function populateOrderFlowFromOrder(o,{confirmation=false}={}){resetOrderForm();editMode=!confirmation;editingOrder=confirmation?null:o;createdOrder=confirmation?o:null;orderCreated=!!confirmation;workItems=orderWorkItems(o).map(i=>({construction:i.constructionType,toothStart:String(i.toothStart),toothEnd:String(i.toothEnd)}));if(!workItems.length)workItems=[{construction:'',toothStart:'',toothEnd:''}];activeWorkItemIndex=workItems.length-1;syncGlobalsFromActive();material=o.material;shade.value=o.shade||'';caseName.value=o.caseName||'';extraNote.value=o.notes||'';impression.value=o.impressionDate||toIsoDate(new Date());deadline.value=o.requestedDeliveryDate||'';selectedDate=deadline.value;if(selectedDate)calendarMonth=monthForIso(selectedDate);document.querySelectorAll('#materialChoices .choice').forEach(x=>x.classList.toggle('active',x.dataset.mat===material));renderShadeChoices();renderWorkItemReadouts();completedSteps.add(1);completedSteps.add(2);completedSteps.add(3);if(confirmation){completedSteps.add(4);completedSteps.add(5);step=5;code.textContent=o.shortenedOrderCode||o.orderCode}else step=1;updateSummary();rememberOrderFlowBaseline()}
